INSERT INTO player_role_map VALUES(1,'2025-26','FC26','role','GK',50,6,'gk_goalkeeper','Defend',NULL,'Closest role to measured heatmap: cosine 0.96 (vs sweeper/Build-Up 0.63). Measured GK footprint is pure goal-line — sweeping is situational. NOTE: descriptive fit; optimal keeps gk_sweeper for the build-up brief.');
INSERT INTO player_role_map VALUES(5,'2025-26','FC26','role','LB',13,32,'fb_att_wb','Support',NULL,'Closest to measured: 0.89 (vs fb_fullback/Versatile 0.64). Digne''s real footprint has more sustained attacking-third left-flank volume than the fullback kernel allows.');
INSERT INTO player_role_map VALUES(4,'2025-26','FC26','role','LCB',37,28,'cb_bpd','Aggressive',NULL,'Closest to measured: 0.91 (Build-Up focus 0.82). Aggressive focus captures his step-ups into midfield.');
INSERT INTO player_role_map VALUES(3,'2025-26','FC26','role','RCB',63,28,'cb_bpd','Aggressive',NULL,'Closest to measured: 0.88 (vs cb_defender/Balanced 0.53). Konsa''s measured step-out carries make him a de facto ball-playing CB — matches the duty review.');
INSERT INTO player_role_map VALUES(2,'2025-26','FC26','role','RB',87,32,'fb_att_wb','Support',NULL,'Closest to measured: 0.94 (vs fb_fullback/Versatile 0.61). Cash''s full-length right-flank coverage reads as an attacking wing-back pattern even in defend-first briefs.');
INSERT INTO player_role_map VALUES(8,'2025-26','FC26','role','LDM',38,42,'dm_dlp','Roaming',NULL,'Closest to measured: 0.72 (vs dm_boxcrasher/Balanced 0.62). Onana''s 6-match all-lane pivot aggregate reads closest to a roaming deep playmaker.');
INSERT INTO player_role_map VALUES(12,'2025-26','FC26','role','RDM',62,42,'dm_dlp','Roaming',NULL,'Closest to measured: 0.83 (vs dm_holding/Ball-Winning 0.58) — EVEN AFTER adding away/tough samples (Chelsea A, Liverpool A). Settles the depth question from player_duties: Kamara moves like a DLP, not a sitting destroyer.');
INSERT INTO player_role_map VALUES(13,'2025-26','FC26','role','LW',15,64,'w_winger','Versatile',NULL,'Closest to measured: 0.65 (vs w_insidefwd/Attack 0.54). His LW-pure grid contains heavy two-way tracking; Versatile winger kernel matches best. Low ceiling of fit (~0.65) = his real movement exceeds any single kernel.');
